    }

msg.url += env.get('type') + '/';

msg.url += env.get('watt') + '/';

msg.url += env.get('latitude') + '/' +
           env.get('longitude') + '/' +
           env.get('declination') + '/' +
           env.get('azimuth') + '/' +
           env.get('modules power');

