var remaining = flow.get('forecast.solar.ratelimit.remaining') || -1;
var limit = flow.get('forecast.solar.ratelimit.limit') || -1

var text = remaining.toString() + '/' + limit.toString();
var fill = "green";

if (remaining == 0) {
    fill = "red";
    text = "Limit used";
}

if (remaining > 0 && remaining < limit / 2) {
    fill = "yellow"
}

if (remaining == -1 ) {
    fill = "blue"
    text = "Limits unknown"
}

msg.payload = ({ fill: fill, text: text });

return msg;

var m = {};
m.labels = [];
m.data = [];

m.series = [];
m.data = [];
m.labels = [];

for (let j = 0; j <= msg.days; j++) {
    m.data[j] = [];
}

if (msg.watt === 'watt_hours_day') {
    var i = 0;
    m.series.push("Watt hours per day");
    for (const key in msg.payload.result) {
        m.labels.push(key);
        if (msg.kwhoutput) {
            m.data[i] = +(Math.round(msg.payload.result[key]/100)*.1).toFixed(1);
        } else {
            m.data[i] = msg.payload.result[key];
        }
        i++;
    }
    m.data = [m.data];
    return { payload: [m] };
}

for (let i = 0; i <= 23; i++) {

    m.labels.push(i.toString()+':00');
    if (msg.resolution === 4) {
       m.labels.push(i.toString()+':15');
    }
    if (msg.resolution === 2 || msg.resolution == 4) {
       m.labels.push(i.toString()+':30');
    }
    if (msg.resolution === 4) {
       m.labels.push(i.toString()+':45');
    }

    for (let j = 0; j <= msg.days; j++) {
        m.data[j].push(0);
        if (msg.resolution === 4) {
           m.data[j].push(0)
        }
        if (msg.resolution === 2 || msg.resolution == 4) {
           m.data[j].push(0)
        }
        if (msg.resolution === 4) {
           m.data[j].push(0)
        }

    }
}

var offset = 0;
for (const key in msg.payload.result) {
    var d = new Date(key)
    if (m.series.indexOf(d.toISOString().split('T')[0]) === -1) {
        m.series.push(d.toISOString().split('T')[0])
    }

    var h = d.getHours();
    var minutes = d.getMinutes();

    if (minutes === 0 ) {
        offset = 0;
    } else {
        offset++;
    }

    if (msg.kwhoutput) {
        m.data[m.series.length - 1][h*msg.resolution+offset] = +(Math.round(msg.payload.result[key]/100)*.1).toFixed(1);
    } else {
        m.data[m.series.length - 1][h*msg.resolution+offset] = msg.payload.result[key];
    }
}

return { payload: [m] };

